document.addEventListener("DOMContentLoaded",(()=>{document.getElementById("select-all").addEventListener("click",(function(){for(var e=document.getElementById("selectedUsers"),t=!0,n=0;n<e.options.length;n++)if(!e.options[n].selected){t=!1;break}for(n=0;n<e.options.length;n++)e.options[n].selected=!t;this.innerHTML=t?'<i class="bi bi-check2-all"></i> Επιλογή Όλων':'<i class="bi bi-eraser"></i> Αποεπιλογή Όλων'}))}));